let all = [];
for (const tz of target) { if (aliases[tz]) all = all.concat(aliases[tz]); else all.push(tz); }
return {targetTimezones: target, allMatchingTimezones: all, utcHour: now.getUTCHours(), runTime: now.toISOString()};

const clients = .first().json;
const checkData = .first().json;
const matchingTimezones = checkData.allMatchingTimezones || [];
if (!Array.isArray(clients) || !clients.length) return [];
